const body = $input.first().json.body || $input.first().json;
const nc = parseInt(body.control_visitors || 0);
const xc = parseInt(body.control_conversions || 0);
const nv = parseInt(body.variant_visitors || 0);
const xv = parseInt(body.variant_conversions || 0);
const alpha = 1 - (parseFloat(body.confidence_target || 95) / 100);

const pc = xc / nc, pv = xv / nv;
const lift = pc > 0 ? ((pv - pc) / pc * 100).toFixed(2) : null;

// Two-proportion z-test
const pp = (xc + xv) / (nc + nv);
const se = Math.sqrt(pp * (1 - pp) * (1/nc + 1/nv));
const z = Math.abs((pv - pc) / se);
// Approximate p-value using normal distribution
const p_value_approx = 2 * (1 - Math.min(0.9999, 0.5 * (1 + Math.sign(z) * Math.sqrt(1 - Math.exp(-z*z*(8/Math.PI+z*z/30)/(4/Math.PI+z*z))))));
const is_significant = p_value_approx <= alpha;
const confidence = ((1 - p_value_approx) * 100).toFixed(1);

let recommendation;
if (!is_significant) { recommendation = 'continue'; }
else if (parseFloat(lift) > 0) { recommendation = 'ship_variant'; }
else { recommendation = 'keep_control'; }

return [{ json: { test_id: `ab_${Date.now()}`, test_name: body.test_name || 'Untitled Test', metric: body.metric || 'conversion_rate', evaluated_at: new Date().toISOString(), control: { visitors: nc, conversions: xc, rate: (pc * 100).toFixed(2) }, variant: { visitors: nv, conversions: xv, rate: (pv * 100).toFixed(2) }, lift_pct: lift, z_score: z.toFixed(3), confidence_pct: parseFloat(confidence), is_statistically_significant: is_significant, confidence_target: body.confidence_target || 95, recommendation, sample_size_note: (nc < 100 || nv < 100) ? 'Sample size may be too small for reliable results' : null } }];

